const items = $input.all();
return items.map(item => ({
  json: {
    ...item.json,
    video_prompt: `Short educational ${item.json.post_type} video clip, TikTok portrait style 9:16. Topic: ${item.json.title ?? item.json.chunk_text.slice(0, 150)}. Style: ${item.json.persona_slug === 'doodle-prof' ? 'animated doodle drawing itself on screen, sketch style, black pen on white paper, comic panels appearing' : item.json.persona_slug === 'meme-lord' ? 'rapid meme montage, bold Impact captions appearing one by one, reaction video format' : item.json.persona_slug === 'exam-gremlin' ? 'fast-paced meme style, bold captions, warning flashes' : item.json.persona_slug === 'lecture-bestie' ? 'friendly explainer with text callouts and icons, pastel lavender background' : item.json.persona_slug === 'study-bard' ? 'music lyric video, lyrics animating to beat, musical notes flying, sky blue and white palette' : 'step-by-step walkthrough with numbered highlights and arrows'}. No faces. 5 seconds.`
  }
}));

const difyResponses = $input.all();
const buildData     = $('Build video prompt').all();

const results = [];
for (let i = 0; i < difyResponses.length; i++) {
  const response = difyResponses[i].json;
  const prev     = buildData[i].json;

  // Dify blocking workflow response: response.data.outputs.<your_output_var>
  // Adjust the key below if your Dify workflow uses a different output variable name
  const outputs  = response?.data?.outputs ?? {};
  const videoUrl = outputs.video_url ?? outputs.url ?? outputs.result ?? null;
  if (!videoUrl) continue;

  results.push({
    json: {
      material_id: prev.material_id,
      persona_id:  prev.persona_id,
      post_type:   prev.post_type,
      title:       prev.title ?? null,
      body:        prev.chunk_text.slice(0, 300),
      media_type:  'video',
      media_url:   videoUrl,
      source:      'n8n',
      sort_order:  prev.chunk_index * 4 + 3,
    }
  });
}
return results;
